    ArgChecker.isTrue(detachmentPoint > attachmentPoint,
        "detachmentPoint ({}) must be greater than attachmentPoint ({})", detachmentPoint, attachmentPoint);

    ResolvedCdsIndex resolvedIndex = underlyingIndex.resolve(refData);
    return ResolvedCdsTranche.builder()
